	appendSessionForTest(t, workDir, agent.SessionIndexEntry{
		ID: "s3", Harness: "agent", Provider: endpointName, Model: "m",
		StartedAt: now.Add(-55 * time.Minute), Tokens: 500, Outcome: "success",
